import React from 'react'
import ReactApexChart from 'react-apexcharts'
import './styles.css'

// This demo also loads: https://cdn.jsdelivr.net/npm/pretty-checkbox@3.0/dist/pretty-checkbox.min.css

const ApexChart = () => {
  const [state, setState] = React.useState({
    series: [
      {
        name: 'Network In',
        data: [],
      },
    ],
    options: {
      chart: {
        type: 'area',
        height: 350,
        animations: {
          enabled: false,
        },
        zoom: {
          enabled: false,
        },
      },
      dataLabels: {
        enabled: false,
      },
      stroke: {
        curve: 'smooth',
      },
      markers: {
        size: 5,
        hover: {
          size: 9,
        },
      },
      title: {
        text: 'Network Monitoring',
      },
      tooltip: {
        intersect: true,
        shared: false,
      },
      theme: {
        palette: 'palette1',
      },
      xaxis: {
        type: 'datetime',
      },
      yaxis: {
        showForNullSeries: false,
        tickAmount: 3,
        min: 0,
        title: {
          text: 'Received MB',
        },
      },
      noData: {
        text: 'No Data',
        style: {
          color: '#FCC',
          fontSize: '24px',
        },
      },
    },
  })

  return (
    <div>
      <div id="chart">
        <ReactApexChart
          options={state.options}
          series={state.series}
          type="area"
          height={350}
        />
      </div>
    </div>
  )
}

export default ApexChart
